 35	export const DateRangeFilter = ({
 36	  filterId,
 37	  helperText,
 38	  onFilterUpdate,
 39	  placeholderLabel,
 40	  selectedFilters = [],
 41	  showFilter = true,
 42	  title,
 43	}: FilterTypeProps) => {
 44	  const validFilters = selectedFilters?.filter(isValidInterval) ?? [];
 45	
 46	  const [from, setFrom] = useState<Date>();
 47	  const [to, setTo] = useState<Date>();
 48	
 49	  const rangeToOption = (range: string) => {
 50	    const formatted = localizeInterval(range);
 51	    return {
 52	      key: range,
 53	      node: (
 54	        <Tooltip content={formatted}>
 55	          <span>{formatted ?? ''}</span>
 56	        </Tooltip>
 57	      ),
 58	    };
 59	  };
 60	  const optionToRange = (option: ToolbarChip): string => option?.key;
 61	
 62	  const clearSingleRange = (option: ToolbarChip) => {
 63	    const target = optionToRange(option);
 64	    onFilterUpdate([...validFilters.filter((range) => range !== target)]);
 65	  };
 66	
 67	  const onFromDateChange: (
 68	    event: FormEvent<HTMLInputElement>,
 69	    value: string,
 70	    date?: Date,
 71	  ) => void = (_event, value) => {
 72	    //see DateFilter onDateChange
 73	    if (value?.length === 10 && isValidDate(value)) {
 74	      setFrom(parseISOtoJSDate(value));
 75	      setTo(undefined);
 76	    }
 77	  };
 78	
 79	  const onToDateChange: (event: FormEvent<HTMLInputElement>, value: string, date?: Date) => void = (
 80	    _event,
 81	    value,
 82	  ) => {
 83	    //see DateFilter onDateChange
 84	    if (value?.length === 10 && isValidDate(value)) {
 85	      const newTo = parseISOtoJSDate(value);
 86	      setTo(newTo);
 87	      const target = toISODateInterval(from, newTo);
 88	      if (target) {
 89	        onFilterUpdate([...validFilters.filter((range) => range !== target), target]);
 90	      }
 91	    }
 92	  };
 93	
 94	  return (
 95	    <ToolbarFilter
 96	      key={filterId}
 97	      labels={validFilters.map(rangeToOption)}
 98	      deleteLabel={(category, option) => {
 99	        clearSingleRange(option as ToolbarChip);
100	      }}
101	      deleteLabelGroup={() => onFilterUpdate([])}
102	      categoryName={title as unknown as string}
103	      showToolbarItem={showFilter}
104	    >
105	      <InputGroup>
106	        <DatePicker
107	          value={toISODate(from)}
108	          dateFormat={(date) => DateTime.fromJSDate(date).toISODate()}
109	          dateParse={(str) => DateTime.fromISO(str).toJSDate()}
110	          onChange={onFromDateChange}
111	          aria-label="Interval start"
112	          placeholder={placeholderLabel}
113	          // disable error text (no space in toolbar scenario)
114	          invalidFormatText={''}
115	          // default value ("parent") creates collision with sticky table header
116	          appendTo={document.body}
117	          popoverProps={{
118	            footerContent: helperText,
119	          }}
120	        />
121	        <DatePicker
122	          value={toISODate(to)}
123	          onChange={onToDateChange}
124	          isDisabled={!isValidJSDate(from)}
125	          // disable error text (no space in toolbar scenario)
126	          invalidFormatText={''}
127	          rangeStart={from}
128	          aria-label="Interval end"
129	          placeholder={placeholderLabel}
130	          appendTo={document.body}
131	          popoverProps={{
132	            footerContent: helperText,
133	          }}
134	        />
135	      </InputGroup>
136	    </ToolbarFilter>
137	  );
138	};

